1	/**
2	 * EDT-04 — verify the 9 plan-canvas tool stubs are de-stubbed in
3	 * PlanCanvas.tsx. The canvas itself depends on three.js + DOM and is
4	 * cumbersome to mount in JSDOM, so this test asserts at the source-file
5	 * level that the previous `console.warn('stub: …')` lines are gone and
6	 * that each tool now dispatches the correct semantic command.
7	 *
8	 * If a future refactor moves these dispatches into helper modules, the
9	 * regex anchors below should be updated to point at the new locations.
10	 */
11	
12	import { readFileSync } from 'node:fs';
13	import * as path from 'node:path';
14	import { fileURLToPath } from 'node:url';
15	import { describe, expect, it } from 'vitest';
16	
17	const __filename = fileURLToPath(import.meta.url);
18	const __dirname = path.dirname(__filename);
19	const SRC = readFileSync(path.join(__dirname, 'PlanCanvas.tsx'), 'utf8');
20	
21	describe('EDT-04 — plan-canvas tool de-stubs', () => {
22	  it('removes every "stub:" console.warn from PlanCanvas.tsx', () => {
23	    expect(SRC).not.toMatch(/console\.warn\(\s*'stub:/);
24	  });
25	
26	  const expectedCommandTypes = [
27	    'splitWallAt',
28	    'alignElementToReference',
29	    'trimElementToReference',
30	    'setWallJoinVariant',
31	    'createWallOpening',
32	    'createColumn',
33	    'createBeam',
34	    'createCeiling',
35	    'createSlabOpening',
36	  ];
37	
38	  for (const cmdType of expectedCommandTypes) {
39	    it(`emits the ${cmdType} semantic command on tool commit`, () => {
40	      const pattern = new RegExp(
41	        String.raw`onSemanticCommand\(\s*\{\s*type:\s*['"]` + cmdType + String.raw`['"]`,
42	      );
43	      expect(SRC).toMatch(pattern);
44	    });
45	  }
46	
